mapper.select:
SELECT id, user_id, name, description, icon, color, doc_count, status,
       is_public, sort_order, create_time, update_time, deleted
FROM knowledge_base
WHERE deleted = 0

    AND name LIKE CONCAT('%', #{params.name}, '%')


    AND user_id = #{params.userId}


    AND status = #{params.status}


    AND is_public = #{params.isPublic}

ORDER BY sort_order ASC, create_time DESC
